import{_ as e,o as t,c as r,ag as l}from"./chunks/framework.DXGyWiRo.js";const i="/images/navi12.png?raw=true",m=JSON.parse('{"title":"12 部署与维护","description":"","frontmatter":{},"headers":[],"relativePath":"12/0.md","filePath":"12/0.md","lastUpdated":null}'),o={name:"12/0.md"};function n(s,a,_,d,h,c){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="_12-部署与维护" tabindex="-1">12 部署与维护 <a class="header-anchor" href="#_12-部署与维护" aria-label="Permalink to &quot;12 部署与维护&quot;">​</a></h1><p>到目前为止，我们前面已经介绍了如何开发程序、调试程序以及测试程序，正如人们常说的：开发最后的10%需要花费90%的时间，所以这一章我们将强调这最后的10%部分，要真正成为让人信任并使用的优秀应用，需要考虑到一些细节，以上所说的10%就是指这些小细节。</p><p>本章我们将通过四个小节来介绍这些小细节的处理，第一小节介绍如何在生产服务上记录程序产生的日志，如何记录日志，第二小节介绍发生错误时我们的程序如何处理，如何保证尽量少的影响到用户的访问，第三小节介绍如何来部署Go的独立程序，由于目前Go程序还无法像C那样写成daemon，那么我们如何管理这样的进程程序后台运行呢？第四小节将介绍应用数据的备份和恢复，尽量保证应用在崩溃的情况能够保持数据的完整性。</p><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><p><img src="'+i+'" alt=""></p><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>上一章: <a href="/11/4.html">第十一章总结</a></li><li>下一节: <a href="/12/1.html">应用日志</a></li></ul>',7)])])}const u=e(o,[["render",n]]);export{m as __pageData,u as default};
